    }", "new_string": "    public override fun toggleWhiteboard() {
        prefWhiteboard = !prefWhiteboard
        Timber.i("Reviewer:: Whiteboard enabled state set to %b", prefWhiteboard)
        // Even though the visibility is now stored in its own setting, we want it to be dependent
        // on the enabled status
        setWhiteboardEnabledState(prefWhiteboard)
        setWhiteboardVisibility(prefWhiteboard)
        if (!prefWhiteboard) {
            colorPalette.visibility = View.GONE
        }
        refreshActionBar()
    }

    private fun toggleAutoAdvance() {
        val currentSetting = sharedPrefs().getBoolean("timeoutAnswer", false)
        val newSetting = !currentSetting
        Timber.i("Reviewer:: Auto advance toggled from %b to %b", currentSetting, newSetting)

        // Update the preference
        sharedPrefs().edit {
            putBoolean("timeoutAnswer", newSetting)
        }

        // Re-create the AutomaticAnswer instance with the new setting
        launchCatchingTask {
            automaticAnswer = AutomaticAnswer.createInstance(this@Reviewer, sharedPrefs(), getColUnsafe)
        }

        // Refresh the action bar to update the menu item title
        refreshActionBar()

        // Show feedback to user
        val message = if (newSetting) {
            getString(R.string.menu_enable_auto_advance)
        } else {
            getString(R.string.menu_disable_auto_advance)
        }
        showSnackbar(message, Snackbar.LENGTH_SHORT)
    }"}

